:root {
  --cm-ink: #2E2A5B;    /* text, hair, pants */
  --cm-blue: #6C8CFF;   /* skin */
  --cm-purple: #A78BFA;
  --cm-pink: #F9A8D4;
  --cm-yellow: #FDE68A;
  --cm-mint: #6EE7B7;
  --cm-bg: #FBFAFF;     /* page ground */
}

.arm {
  width: 14px; height: 96px;            /* ~2x natural length */
  background: var(--cm-blue);           /* flat non-natural skin */
  border-radius: 999px;                 /* the capsule IS the limb */
  transform: rotate(38deg);
  transform-origin: top center;
  box-shadow: none; border: none;       /* no shading, no outline */
}

.riso-pink { color: #ff4da6; transform: translate(-1.5px, -1px); }
.riso-cyan { color: #00b4d8; transform: translate(1.5px, 1px); }
.riso-yellow { color: #ffd60a; transform: translate(0, -1.5px); }

